mapper.select:
SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT p.PAGE_ID AS pageId, p.PAGE_NAME AS pageName, p.CREATE_USER_NAME AS createUserName, TO_CHAR(p.BEGINNING_DATE, 'YYYY-MM-DD') AS beginningDate, TO_CHAR(p.EXPIRED_DATE, 'YYYY-MM-DD') AS expiredDate,
si.INSTANCE_ID AS instanceId, si.INSTANCE_IP AS instanceIp, si.INSTANCE_PORT AS instancePort FROM SPW_CMS_PAGE p LEFT JOIN LATERAL ( SELECT FILE_ID, INSTANCE_ID FROM FWK_CMS_FILE_SEND_HIS WHERE FILE_ID LIKE p.PAGE_ID || '%.html' OR FILE_ID LIKE p.PAGE_ID || '%.tsx' ORDER BY LAST_MODIFIED_DTIME DESC FETCH FIRST 1 ROW ONLY ) lh ON 1=1 LEFT JOIN FWK_CMS_SERVER_INSTANCE si ON lh.INSTANCE_ID = si.INSTANCE_ID
ORDER BY p.LAST_MODIFIED_DTIME DESC NULLS LAST ) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}
